import requests

BASE_URL = "http://localhost:8000"
TOKEN = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..r2Ewgt6G-K7oypEt_rbzpJ8VhktrEF6qBGpAt8AdvL4"
HEADERS = {
    "Authorization": f"Bearer {TOKEN}",
    "Accept": "application/json"
}
TIMEOUT = 30

def test_get_sales_orders_list_filtered_by_status():
    url = f"{BASE_URL}/api/sales/orders"
    params = {
        "status": "open"
    }
    try:
        response = requests.get(url, headers=HEADERS, params=params, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"

    assert response.status_code == 200, f"Expected status code 200 but got {response.status_code}"
    try:
        json_data = response.json()
    except ValueError:
        assert False, "Response is not valid JSON"

    assert isinstance(json_data, list), f"Expected response JSON to be a list but got {type(json_data)}"
    # Validate each item in the list is dictionary with expected keys (at minimum id and status)
    for order in json_data:
        assert isinstance(order, dict), f"Each sales order should be a dict, got {type(order)}"
        assert "id" in order, "Sales order missing 'id' field"
        assert "status" in order, "Sales order missing 'status' field"
        assert order["status"] == "open", f"Sales order status expected to be 'open', got '{order['status']}'"

test_get_sales_orders_list_filtered_by_status()
